INSERT INTO agent_registry (id, name, layer, pole, platform, fallback_platform, model, instructions, tone, languages, perimeter, knowledge, status, livrables_jour) VALUES
('L1-01', 'Calibrateur NOOS', 'L1', 'Neurosciences & Santé', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Production documentaire et calculs statistiques. Claude Projects sert de mémoire des items déjà calibrés. Calibre les 3000 items SCID-5 adaptés au scoring algorithmique. Vérifie la cohérence interne (alpha de Cronbach, corrélations item-total) et exporte en format compatible avec le moteur de scoring Rust.', 'technique', '{"fr","en"}', '{"noos"}', '{"SCID-5","DSM-5-TR","CIM-11","items psychométriques","psychométrie classique","IRT"}', 'inactive', 16),
('L1-02', 'Architecte UX patient', 'L1', 'Neurosciences & Santé', 'Antigravity', 'Figma', 'gemini-2.5-pro', 'Conçoit les maquettes UI/UX du portail patient NOOS. Respecte les principes de design trauma-informed (couleurs apaisantes, navigation prévisible, pas de dark patterns). Produit wireframes, prototypes interactifs et spécifications pour les développeurs React.', 'empathique-technique', '{"fr","en"}', '{"noos"}', '{"design thinking","UX santé mentale","WCAG 2.2","trauma-informed design","Material Design Health"}', 'inactive', 8),
('L1-03', 'Neuroscientifique computationnel', 'L1', 'Neurosciences & Santé', 'Claude Code', 'Jupyter', 'claude-opus-4-6', 'Développe les modèles bayésiens du moteur diagnostique NOOS en Python (pgmpy, PyMC). Implémente les réseaux bayésiens dynamiques reliant symptômes SCID-5, biomarqueurs et trajectoires patient. Valide par simulation Monte Carlo et cross-validation clinique.', 'scientifique', '{"fr","en"}', '{"noos"}', '{"réseaux bayésiens","pgmpy","PyMC","modèles graphiques probabilistes","neurosciences computationnelles","DSM-5-TR"}', 'inactive', 12),
('L1-04', 'Chercheur SCID-5', 'L1', 'Neurosciences & Santé', 'Perplexity', 'Google Scholar', 'multi-model', 'Recherche systématique sur PubMed, Cochrane, PsycINFO. Produit des revues de littérature structurées sur la validité et fiabilité du SCID-5, les adaptations culturelles (Maghreb, Afrique subsaharienne), et les innovations en diagnostic assisté par IA. Formate en fiches exploitables pour le calibrateur.', 'académique', '{"fr","en"}', '{"noos"}', '{"SCID-5","PubMed","Cochrane","méta-analyses","psychométrie transculturelle"}', 'inactive', 20),
('L1-05', 'Ingénieur NLP clinique', 'L1', 'Neurosciences & Santé', 'Claude Code', 'Colab', 'claude-opus-4-6', 'Fine-tune des modèles HuggingFace et MLX pour l''analyse sémantique des entretiens cliniques. Entraîne des classifieurs de symptômes sur corpus annotés. Optimise l''inférence pour déploiement edge (quantization INT4/INT8). Pipeline complet : tokenization darija/français → embedding → classification multi-label.', 'technique', '{"fr","en"}', '{"noos","myne"}', '{"HuggingFace Transformers","MLX","NLP clinique","fine-tuning LoRA","GGUF","spaCy"}', 'inactive', 10),
('L1-06', 'Data engineer MYNε', 'L1', 'Neurosciences & Santé', 'Claude Code', 'VS Code', 'claude-opus-4-6', 'Conçoit et implémente les pipelines de données MYNε en Rust. Intègre ARX pour l''anonymisation k-anonymat/l-diversité des données patient. Assure la conformité RGPD dès la conception (privacy by design). Optimise les flux ETL pour ingestion temps réel depuis les portails cliniques vers Supabase.', 'technique', '{"fr","en"}', '{"myne"}', '{"Rust","ARX anonymisation","k-anonymat","l-diversité","RGPD","ETL","Supabase","Apache Arrow"}', 'inactive', 12),
('L1-07', 'Spécialiste observance', 'L1', 'Neurosciences & Santé', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Rédige les user stories et spécifications fonctionnelles du module d''observance thérapeutique NOOS. Benchmark les solutions existantes (MyTherapy, Medisafe, Ada Health). Définit les métriques d''engagement patient et les nudges comportementaux basés sur les sciences comportementales.', 'technique', '{"fr","en"}', '{"noos"}', '{"observance thérapeutique","behavioral design","nudge theory","mHealth","patient engagement"}', 'inactive', 16),
('L1-08', 'Chercheur fertilité LALLA', 'L1', 'Neurosciences & Santé', 'Perplexity', 'Google Scholar', 'multi-model', 'Recherche exhaustive sur la littérature fertilité et IA : prédiction ovulatoire, biomarqueurs hormonaux, PMA assistée par ML. Couvre les bases Cochrane, ESHRE, ASRM. Produit des synthèses exploitables pour l''architecture LALLA. Focus particulier sur les données épidémiologiques Maghreb et Afrique.', 'académique', '{"fr","en"}', '{"lalla"}', '{"fertilité","PMA","endocrinologie reproductive","IA prédictive","ESHRE guidelines"}', 'inactive', 20),
('L1-09', 'Spécialiste trauma SAWT', 'L1', 'Neurosciences & Santé', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Rédaction spécialisée trauma-informed pour le module SAWT. Produit les contenus psychoéducatifs, les scripts de chatbot thérapeutique (CBT, EMDR-inspired), et les protocoles de sécurité (détection crise suicidaire, escalade vers humain). Respecte strictement les guidelines OMS et APA sur le trauma.', 'empathique-rigoureux', '{"fr","en","ar"}', '{"sawt"}', '{"PTSD","trauma complexe","CBT","EMDR","safety planning","OMS guidelines trauma"}', 'inactive', 14),
('L1-10', 'Analyste addictologie NAFAS', 'L1', 'Neurosciences & Santé', 'Perplexity', 'Google Scholar', 'multi-model', 'Benchmark exhaustif des applications de sevrage et réduction des risques (Smoke Free, I Am Sober, reSET-O). Analyse des modèles cliniques (stades de Prochaska, entretien motivationnel). Veille sur les interventions digitales en addictologie. Produit fiches comparatives et recommandations pour NAFAS.', 'analytique', '{"fr","en"}', '{"nafas"}', '{"addictologie","DTx","entretien motivationnel","Prochaska","réduction des risques","FDA DTx guidelines"}', 'inactive', 20),
('L1-11', 'Ingénieur Rust NOOS', 'L1', 'IA & Ingénierie', 'Claude Code', 'VS Code', 'claude-opus-4-6', 'Développe le scoring engine NOOS en Rust pur. Contrainte stricte : latence <2ms par évaluation diagnostique. Implémente les arbres de décision SCID-5 en structures zero-copy. Tests de charge à 10k requêtes/seconde. Intégration FFI avec le backend TypeScript via napi-rs.', 'technique', '{"fr","en"}', '{"noos"}', '{"Rust","zero-copy","napi-rs","benchmarking","arbres de décision","latence sub-milliseconde"}', 'inactive', 10),
('L1-12', 'Ingénieur TypeScript API', 'L1', 'IA & Ingénierie', 'Codex', 'Claude Code', 'gpt-5.2', 'Développe les API REST/GraphQL en TypeScript avec Fastify. Produit le boilerplate, les schémas Zod, les handlers et les tests unitaires (Vitest). Architecture hexagonale avec injection de dépendances. Documentation OpenAPI auto-générée. Couvre les 6 entités Eigen.', 'technique', '{"fr","en"}', '{"noos","aelya","myne","burhan","lalla","sawt"}', '{"TypeScript","Fastify","Zod","Vitest","OpenAPI","architecture hexagonale","GraphQL"}', 'inactive', 14),
('L1-13', 'Ingénieur React portails', 'L1', 'IA & Ingénierie', 'Antigravity', 'Claude Code', 'gemini-2.5-pro', 'Build-test loop continu pour les 6 portails web Eigen (NOOS patient, NOOS clinicien, ÆLYA wallet, MYNε dashboard, BURHAN explorer, portail unifié). React 19 + Next.js 15 + Tailwind. Composants accessibles (ARIA), responsive, et optimisés (Core Web Vitals LCP <2.5s).', 'technique', '{"fr","en"}', '{"noos","aelya","myne","burhan"}', '{"React 19","Next.js 15","Tailwind CSS","ARIA","Core Web Vitals","design system"}', 'inactive', 12),
('L1-14', 'Architecte BURHAN Solidity', 'L1', 'IA & Ingénierie', 'Codex', 'Claude Code', 'gpt-5.2', 'Développe les smart contracts BURHAN en Solidity 0.8.x. Architecture : token ERC-20 gouvernance, staking, trésorerie DAO, oracle santé. Tests Hardhat avec couverture >95%. Audit gas optimization. Déploiement sur testnet Sepolia puis mainnet Polygon/Arbitrum.', 'technique', '{"fr","en"}', '{"burhan"}', '{"Solidity","Hardhat","OpenZeppelin","ERC-20","DAO","Polygon","Arbitrum","gas optimization"}', 'inactive', 10),
('L1-15', 'Ingénieur ÆLYA ZKP', 'L1', 'IA & Ingénierie', 'Claude Code', 'VS Code', 'claude-opus-4-6', 'Implémente les circuits zero-knowledge pour ÆLYA : preuves de diagnostic sans révélation de données patient (Groth16 pour performance, PLONK pour universalité). Stack : circom/snarkjs ou halo2. Intégration avec le wallet ÆLYA pour vérification on-chain. Benchmark : proof generation <5s sur hardware patient standard.', 'technique', '{"fr","en"}', '{"aelya"}', '{"ZKP","Groth16","PLONK","circom","snarkjs","halo2","cryptographie","privacy-preserving computation"}', 'inactive', 8),
('L1-16', 'DevSecOps', 'L1', 'IA & Ingénierie', 'Codex', 'Claude Code', 'gpt-5.2', 'Gère l''infrastructure CI/CD complète Eigen. Pipelines GitHub Actions, Dockerfiles multi-stage, IaC Terraform pour AWS/Scaleway. Monitoring Prometheus+Grafana. Secrets management avec Vault. Scans SAST/DAST automatisés (Semgrep, Trivy). Objectif : zero-downtime deployment.', 'technique', '{"fr","en"}', '{"infra"}', '{"Docker","Terraform","GitHub Actions","Prometheus","Grafana","Vault","Semgrep","Trivy","AWS","Scaleway"}', 'inactive', 14),
('L1-17', 'DBA PostgreSQL', 'L1', 'IA & Ingénierie', 'Claude Code', 'pgAdmin', 'claude-sonnet-4-6', 'Optimise l''instance Supabase PostgreSQL. Conçoit les schémas, index (B-tree, GIN, GiST), politiques RLS par rôle (patient, clinicien, admin, chercheur). Requêtes EXPLAIN ANALYZE pour optimisation. Partitionnement des tables volumineuses. Backup strategy et disaster recovery.', 'technique', '{"fr","en"}', '{"infra","myne"}', '{"PostgreSQL","Supabase","RLS","indexation","partitionnement","pg_stat_statements","pgbouncer"}', 'inactive', 16),
('L1-18', 'Ingénieur MLX/LoRA', 'L1', 'IA & Ingénierie', 'Claude Code', 'Terminal', 'claude-opus-4-6', 'Fine-tune de modèles LLM locaux sur Mac Apple Silicon via MLX. Adapte Mistral/Llama pour les cas d''usage Eigen : classification diagnostique, extraction d''entités cliniques, génération de rapports. LoRA rank optimization, quantization 4-bit, évaluation sur benchmarks cliniques maison.', 'technique', '{"fr","en"}', '{"noos","myne"}', '{"MLX","LoRA","QLoRA","Mistral","Llama","Apple Silicon","quantization","PEFT"}', 'inactive', 8),
('L1-19', 'QA automaticien', 'L1', 'IA & Ingénierie', 'Codex', 'Claude Code', 'gpt-5.2', 'Écrit et maintient la suite de tests complète Eigen. Tests unitaires Vitest, tests d''intégration, tests E2E Playwright sur les 6 portails. Coverage minimum 80%. Tests de régression automatisés sur chaque PR. Rapports de qualité quotidiens avec métriques de dette technique.', 'technique', '{"fr","en"}', '{"noos","aelya","myne","burhan"}', '{"Vitest","Playwright","testing library","coverage Istanbul","CI testing","mutation testing"}', 'inactive', 18),
('L1-20', 'Ingénieur MCP/A2A', 'L1', 'IA & Ingénierie', 'Claude Code', 'VS Code', 'claude-opus-4-6', 'Implémente les protocoles de communication inter-agents : MCP (Model Context Protocol) pour les outils, A2A (Agent-to-Agent) pour la coordination L0-L1-L2. Conçoit les schémas de messages, les mécanismes de retry/fallback, et le bus événementiel. Monitoring de la santé du réseau d''agents.', 'technique', '{"fr","en"}', '{"infra"}', '{"MCP","A2A","protocoles inter-agents","event bus","message queuing","circuit breaker"}', 'inactive', 10),
('L1-21', 'Architecte Web 4.0', 'L1', 'IA & Ingénierie', 'Claude Code', 'Miro', 'claude-opus-4-6', 'Conçoit l''architecture d''ensemble intégrant ÆLYA (identité décentralisée) + MYNε (données souveraines) + BURHAN (gouvernance blockchain). Définit les interfaces entre composants Web2 et Web3. Produit les ADR (Architecture Decision Records), diagrammes C4, et spécifications d''intégration.', 'technique', '{"fr","en"}', '{"aelya","myne","burhan"}', '{"architecture distribuée","DID","Verifiable Credentials","IPFS","diagrammes C4","ADR","Web3 stack"}', 'inactive', 10),
('L1-22', 'Ingénieur mobile React Native', 'L1', 'IA & Ingénierie', 'Codex', 'Claude Code', 'gpt-5.2', 'Développe l''application mobile patient NOOS en React Native (Expo). Fonctionnalités : questionnaires adaptatifs, suivi d''humeur, notifications push thérapeutiques, mode hors-ligne avec sync. Accessibilité WCAG 2.2 mobile. Build iOS + Android. Tests Detox.', 'technique', '{"fr","en"}', '{"noos"}', '{"React Native","Expo","Detox","push notifications","offline-first","SQLite","WCAG mobile"}', 'inactive', 12),
('L1-23', 'DPO RGPD', 'L1', 'Données & Conformité', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Rédige les AIPD (Analyses d''Impact sur la Protection des Données) pour chaque entité Eigen. Maintient les registres de traitements Article 30. Produit les clauses contractuelles types, les politiques de confidentialité, et les procédures de réponse aux droits des personnes. Interlocuteur CNIL simulé.', 'juridique', '{"fr","en"}', '{"noos","aelya","myne","burhan","lalla","sawt"}', '{"RGPD","AIPD","CNIL","Article 30","Privacy by Design","clauses contractuelles types","DPO"}', 'inactive', 12),
('L1-24', 'Analyste AI Act', 'L1', 'Données & Conformité', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Classifie chaque composant IA Eigen selon la taxonomie de risque AI Act (inacceptable, haut risque, risque limité, risque minimal). NOOS = haut risque (santé). Produit la documentation technique exigée : système de gestion des risques, données d''entraînement, transparence, supervision humaine. Prépare les dossiers de conformité CE.', 'juridique-technique', '{"fr","en"}', '{"noos","myne","aelya"}', '{"AI Act","classification risque IA","marquage CE","documentation technique IA","supervision humaine","Annexe III"}', 'inactive', 14),
('L1-25', 'Analyste MiCA', 'L1', 'Données & Conformité', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Audit de conformité BURHAN au règlement MiCA (Markets in Crypto-Assets). Classification du token BURHAN (utility vs. asset-referenced vs. e-money). Rédaction du white paper conforme Article 6. Analyse des obligations d''émetteur, réserves, et gouvernance. Cartographie des licences nécessaires par juridiction.', 'juridique', '{"fr","en"}', '{"burhan"}', '{"MiCA","classification tokens","white paper réglementaire","CASP","AMF","ESMA","réserves prudentielles"}', 'inactive', 12),
('L1-26', 'Spécialiste ISO 13485', 'L1', 'Données & Conformité', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Met en place le QMS (Quality Management System) conforme ISO 13485 pour NOOS en tant que dispositif médical SaMD (Software as Medical Device). Rédige les procédures qualité, les dossiers de conception (design history file), la gestion des risques ISO 14971, et prépare l''audit de certification.', 'réglementaire', '{"fr","en"}', '{"noos"}', '{"ISO 13485","ISO 14971","SaMD","IEC 62304","design controls","CAPA","FDA 510(k)","marquage CE MDR"}', 'inactive', 10),
('L1-27', 'Cartographe données', 'L1', 'Données & Conformité', 'Claude Code', 'dbt', 'claude-sonnet-4-6', 'Inventorie toutes les données circulant dans l''écosystème Eigen. Produit le data lineage complet (source → transformation → destination). Cartographie les flux inter-entités. Identifie les données sensibles (santé, financières, identité) et vérifie la cohérence avec les registres RGPD. Utilise dbt pour documenter les transformations.', 'technique', '{"fr","en"}', '{"myne","noos","aelya","burhan"}', '{"data lineage","data catalog","dbt","metadata management","données sensibles","RGPD Article 30"}', 'inactive', 14),
('L1-28', 'Analyste KYC/AML', 'L1', 'Données & Conformité', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Conçoit les procédures KYC (Know Your Customer) et AML (Anti-Money Laundering) pour BURHAN et ÆLYA. Due diligence sur les utilisateurs du wallet et de la DAO. Conformité 5ème directive anti-blanchiment, TRACFIN, et réglementations MENA. Screening des sanctions (OFAC, UE, ONU).', 'juridique', '{"fr","en"}', '{"burhan","aelya"}', '{"KYC","AML","5AMLD","TRACFIN","screening sanctions","OFAC","FATF","due diligence"}', 'inactive', 12),
('L1-29', 'Veilleur réglementaire', 'L1', 'Données & Conformité', 'Perplexity', 'Google Alerts', 'multi-model', 'Veille quotidienne sur les évolutions réglementaires FR/EU/MA impactant Eigen. Couvre : AI Act (actes délégués), RGPD (décisions CJUE), MiCA (RTS/ITS ESMA), MDR (MDCG guidelines), loi 09-08 Maroc (CNDP). Produit un bulletin quotidien priorisé par impact sur les entités Eigen.', 'synthétique', '{"fr","en"}', '{"noos","aelya","myne","burhan"}', '{"veille réglementaire","AI Act","RGPD","MiCA","MDR","loi 09-08","CNDP Maroc","CJUE"}', 'inactive', 22),
('L1-30', 'Data quality analyst', 'L1', 'Données & Conformité', 'Claude Code', 'Great Expectations', 'claude-sonnet-4-6', 'Définit et monitore les métriques de qualité des données Eigen : complétude, cohérence, fraîcheur, unicité, validité. Implémente les contrôles Great Expectations sur les pipelines. Détecte les anomalies (data drift, outliers, valeurs manquantes). Rapports quotidiens de santé des données avec alertes.', 'technique', '{"fr","en"}', '{"myne"}', '{"Great Expectations","data quality","data observability","anomaly detection","SPC","métriques DQ"}', 'inactive', 16),
('L1-31', 'Analyste concurrentiel NOOS', 'L1', 'Marché & Acquisition', 'Perplexity', 'Crunchbase', 'multi-model', 'Benchmark exhaustif des concurrents en psychiatrie digitale EU : Woebot, Wysa, Mindstrong, Ginger, Talkspace, BetterHelp, Healios. Analyse par critères : modèle clinique, stack technique, pricing, levées de fonds, marchés cibles, résultats cliniques publiés. Mise à jour mensuelle de la matrice concurrentielle.', 'analytique', '{"fr","en"}', '{"noos"}', '{"digital mental health","competitive intelligence","Crunchbase","PitchBook","analyse concurrentielle"}', 'inactive', 18),
('L1-32', 'Analyste TAM/SAM/SOM', 'L1', 'Marché & Acquisition', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Sizing marché bottom-up et top-down pour chaque entité Eigen. Sources : Statista, Grand View Research, WHO, HCP Maroc, Eurostat. Modélise TAM/SAM/SOM avec hypothèses explicites et scénarios (conservateur, base, optimiste). Produit les slides marché pour les pitch decks investisseurs.', 'analytique', '{"fr","en"}', '{"noos","aelya","myne","burhan","lalla","sawt"}', '{"TAM/SAM/SOM","market sizing","Statista","modélisation financière","healthcare market"}', 'inactive', 14),
('L1-33', 'Chasseur VC', 'L1', 'Marché & Acquisition', 'Perplexity', 'Crunchbase', 'multi-model', 'Profiling systématique des fonds VC healthtech et deeptech : thèse d''investissement, ticket moyen, stade, portfolio, partners. Cibles prioritaires : fonds EU (Partech Health, Elaia, Sofinnova), MENA (Flat6Labs, 212 Founders, UM6P Ventures), US (a16z bio, GV). Produit fiches de 1 page par fonds avec angle d''approche.', 'business', '{"fr","en"}', '{"fundraising"}', '{"venture capital","healthtech VC","deeptech VC","due diligence investisseur","term sheets"}', 'inactive', 20),
('L1-34', 'Profiler GITEX', 'L1', 'Marché & Acquisition', 'Perplexity', 'LinkedIn', 'multi-model', 'Produit les fiches profil des 1000 cibles entreprises pour GITEX Africa et autres salons stratégiques. Par cible : activité, CA, décideurs, besoins potentiels, angle Eigen pertinent. Priorise par probabilité de conversion et taille de deal. Exporte en format CRM-ready (CSV structuré).', 'commercial', '{"fr","en"}', '{"business development"}', '{"GITEX","prospection B2B","profiling entreprise","CRM","salons professionnels"}', 'inactive', 25),
('L1-35', 'Rédacteur pitch deck', 'L1', 'Marché & Acquisition', 'Antigravity', 'Cowork', 'gemini-2.5-pro', 'Conçoit les slides investisseurs pour chaque entité Eigen et le groupe. Structure Sequoia (problem, solution, market, product, traction, team, financials, ask). Design épuré, data-driven, storytelling percutant. Versions FR/EN. Adaptation par audience (seed, Series A, corporate VC, family office).', 'persuasif-factuel', '{"fr","en"}', '{"fundraising"}', '{"pitch deck","storytelling investisseur","Sequoia framework","design slides","métriques SaaS"}', 'inactive', 6),
('L1-36', 'Analyste M&A', 'L1', 'Marché & Acquisition', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Analyse des opportunités M&A pour Eigen : cibles d''acquisition (startups santé digitale en difficulté, datasets cliniques, licences SaMD). Produit les comparables de valorisation (multiples ARR, EV/Revenue), modèles DCF simplifiés, et scénarios d''exit (IPO, acquisition stratégique, secondary).', 'financier', '{"fr","en"}', '{"fundraising","stratégie"}', '{"M&A","valorisation startup","DCF","comparables","multiples SaaS","exit scenarios"}', 'inactive', 10),
('L1-37', 'Business developer corridor', 'L1', 'Marché & Acquisition', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Produit les fiches pays pour les 22 pays du corridor Afrique-Europe. Par pays : environnement réglementaire santé/fintech, contacts institutionnels clés, partenaires potentiels, barrières à l''entrée. Prépare les dossiers d''introduction et les stratégies de go-to-market locales.', 'business', '{"fr","en"}', '{"corridor"}', '{"business development Afrique","go-to-market","partenariats institutionnels","corridor Afrique-Europe"}', 'inactive', 14),
('L1-38', 'Growth hacker', 'L1', 'Marché & Acquisition', 'Codex', 'Claude Code', 'gpt-5.2', 'Développe les scripts d''acquisition et d''analytics : scraping éthique (respect robots.txt), automatisation LinkedIn, séquences email (Lemlist/Instantly), tracking UTM, dashboards Mixpanel/Amplitude. A/B testing landing pages. Objectif : CAC < LTV/3 sur chaque canal.', 'growth', '{"fr","en"}', '{"acquisition"}', '{"growth hacking","scraping éthique","email automation","Mixpanel","A/B testing","funnel optimization"}', 'inactive', 16),
('L1-39', 'Pricing analyst', 'L1', 'Marché & Acquisition', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Modélise les stratégies pricing pour chaque entité Eigen. NOOS : B2B2C (hôpitaux, mutuelles) + B2C freemium. BURHAN : tokenomics et fee structure. ÆLYA : subscription tiers. Analyse willingness-to-pay, élasticité prix, benchmarks concurrents. Simulations P&L par scénario pricing.', 'analytique', '{"fr","en"}', '{"noos","aelya","myne","burhan"}', '{"pricing SaaS","tokenomics","willingness-to-pay","Van Westendorp","conjoint analysis","P&L modeling"}', 'inactive', 12),
('L1-40', 'LP relationship manager', 'L1', 'Marché & Acquisition', 'Cowork', 'Perplexity', 'claude-opus-4-6', 'Gère la relation avec les Limited Partners potentiels et existants. Produit les fiches LP (family offices, institutionnels, HNW), le reporting trimestriel standardisé (ILPA), les documents de souscription, et les Q&A investisseurs. Suivi du pipeline de levée de fonds.', 'institutionnel', '{"fr","en"}', '{"fundraising"}', '{"LP relations","ILPA reporting","fund administration","souscription","carried interest","waterfall"}', 'inactive', 14)
